function binpow(a, b) {
    let res = 1n; // Use BigInt for large numbers
    let base = BigInt(a);
    let exp = BigInt(b);

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = res * base;
        }
        base = base * base;
        exp = exp / 2n;
    }
    return res;
}

